import { exportJWK, importSPKI } from "jose";

const DEFAULT_JWKS_KID = "dashboard-jwt-signing-key";

export async function createJwksDocument(
  publicKeyPem: string,
  kid: string = DEFAULT_JWKS_KID,
): Promise<{ keys: Array<Record<string, unknown>> }> {
  const publicKey = await importSPKI(publicKeyPem, "RS256");
  const jwk = await exportJWK(publicKey);
  return {
    keys: [{ ...jwk, kid, use: "sig", alg: "RS256" }],
  };
}

import { exportSPKI, generateKeyPair, jwtVerify } from "jose";
import { describe, expect, it } from "vitest";
import { createJwksDocument } from "./jwks.js";

describe("createJwksDocument", () => {
  it("exports a JWKS document that verifies tokens signed with the matching private key", async () => {
    const keyPair = await generateKeyPair("RS256", { extractable: true });
    const publicKeyPem = await exportSPKI(keyPair.publicKey);
    const jwks = await createJwksDocument(publicKeyPem);

    expect(Array.isArray(jwks.keys)).toBe(true);
    expect(jwks.keys).toHaveLength(1);
    expect(jwks.keys[0]?.kid).toBe("dashboard-jwt-signing-key");

    const { payload } = await jwtVerify(
      await new (await import("jose")).SignJWT({ role: "guide" })
        .setProtectedHeader({ alg: "RS256", kid: "dashboard-jwt-signing-key" })
        .setIssuer("http://localhost:3000")
        .setAudience("memories-api")
        .setSubject("62990eb0-46e8-4868-8168-c487d0bd31a4")
        .setIssuedAt(Math.floor(Date.now() / 1000))
        .setExpirationTime(Math.floor(Date.now() / 1000) + 60)
        .setJti("62990eb0-46e8-4868-8168-c487d0bd31a5")
        .sign(keyPair.privateKey),
      (await import("jose")).createLocalJWKSet(jwks),
      {
        issuer: "http://localhost:3000",
        audience: "memories-api",
      },
    );

    expect(payload.role).toBe("guide");
  });
});

